```python
text = 'hello'
char_count = {}

for char in text:
    if char in char_count:
        char_count[char] += 1
    else:
        char_count[char] = 1

print(char_count)  
# Output: {'h': 1, 'e': 1, 'l': 2, 'o': 1}

# Alternative using .get():
# for char in text:
#     char_count[char] = char_count.get(char, 0) + 1
